import React, { useEffect, useState } from 'react';
import { venueAPI, reservationAPI, storyAPI } from '../services/api';
import { toast } from 'react-toastify';

export default function VenueOwnerDashboard() {
  const [venues, setVenues] = useState([]);
  const [selectedVenue, setSelectedVenue] = useState(null);
  const [reservations, setReservations] = useState([]);
  const [tab, setTab] = useState('overview');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVenues = async () => {
      try {
        const res = await venueAPI.myVenues();
        setVenues(res.data.results || res.data);
        if (res.data.results?.length > 0 || res.data?.length > 0) {
          setSelectedVenue((res.data.results || res.data)[0]);
        }
      } catch (err) {
        toast.error('Failed to load venues.');
      } finally {
        setLoading(false);
      }
    };
    fetchVenues();
  }, []);

  useEffect(() => {
    if (selectedVenue?.slug) {
      reservationAPI.venueReservations(selectedVenue.slug).then((res) => {
        setReservations(res.data.results || res.data);
      });
    }
  }, [selectedVenue]);

  const handleToggleOpen = async () => {
    try {
      const res = await venueAPI.toggleOpen(selectedVenue.slug);
      setSelectedVenue({ ...selectedVenue, is_open: res.data.is_open });
      toast.success(res.data.is_open ? 'Venue is now open!' : 'Venue is now closed.');
    } catch {
      toast.error('Failed to update status.');
    }
  };

  const handleUpdateBusyLevel = async (level) => {
    try {
      await venueAPI.updateBusyLevel(selectedVenue.slug, level);
      setSelectedVenue({ ...selectedVenue, busy_level: level });
    } catch {
      toast.error('Failed to update busy level.');
    }
  };

  const handleReservationStatus = async (id, status) => {
    try {
      await reservationAPI.updateStatus(id, { status });
      setReservations(reservations.map((r) => r.id === id ? { ...r, status } : r));
      toast.success(`Reservation ${status}.`);
    } catch {
      toast.error('Failed to update reservation.');
    }
  };

  if (loading) {
    return (
      <div className="pt-20 min-h-screen max-w-7xl mx-auto px-4 py-8">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-dark-card rounded w-1/3" />
          <div className="h-48 bg-dark-card rounded-2xl" />
        </div>
      </div>
    );
  }

  return (
    <div className="pt-20 min-h-screen max-w-7xl mx-auto px-4 py-8">
      <div className="flex items-center justify-between mb-8">
        <h1 className="font-display font-bold text-3xl text-white">Venue Dashboard</h1>
        <button className="btn-primary">+ Add New Venue</button>
      </div>

      {venues.length === 0 ? (
        <div className="text-center py-20 card">
          <p className="text-5xl mb-4">🏢</p>
          <p className="text-white text-xl mb-2">No venues yet</p>
          <p className="text-gray-500 mb-6">List your first venue and start accepting reservations.</p>
          <button className="btn-primary">Create Your Venue Profile</button>
        </div>
      ) : (
        <div className="flex flex-col lg:flex-row gap-6">
          {/* Venue selector */}
          <aside className="w-full lg:w-64 flex-shrink-0">
            <div className="card p-2 space-y-1">
              {venues.map((venue) => (
                <button
                  key={venue.id}
                  onClick={() => setSelectedVenue(venue)}
                  className={`w-full text-left p-3 rounded-xl transition-colors ${
                    selectedVenue?.id === venue.id ? 'bg-primary/20 text-primary' : 'text-gray-400 hover:text-white hover:bg-dark-border'
                  }`}
                >
                  <p className="font-medium text-sm">{venue.name}</p>
                  <p className="text-xs mt-0.5 opacity-70">{venue.city}</p>
                </button>
              ))}
            </div>
          </aside>

          {/* Main content */}
          {selectedVenue && (
            <main className="flex-1 space-y-6">
              {/* Status controls */}
              <div className="card p-5 flex flex-wrap gap-4 items-center justify-between">
                <div>
                  <h2 className="font-display font-bold text-2xl text-white">{selectedVenue.name}</h2>
                  <p className="text-gray-500 text-sm">{selectedVenue.city} · {selectedVenue.status}</p>
                </div>
                <div className="flex items-center gap-3">
                  <button
                    onClick={handleToggleOpen}
                    className={`px-5 py-2.5 rounded-xl font-semibold text-sm transition-all ${
                      selectedVenue.is_open
                        ? 'bg-red-500/20 border border-red-500/40 text-red-400 hover:bg-red-500/30'
                        : 'bg-green-500/20 border border-green-500/40 text-green-400 hover:bg-green-500/30'
                    }`}
                  >
                    {selectedVenue.is_open ? 'Close Venue' : 'Open Venue'}
                  </button>
                </div>
              </div>

              {/* Busy level control */}
              <div className="card p-5">
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-semibold text-white">Busy Level</h3>
                  <span className="text-primary font-bold">{selectedVenue.busy_level}%</span>
                </div>
                <input
                  type="range"
                  min="0"
                  max="100"
                  value={selectedVenue.busy_level}
                  onChange={(e) => handleUpdateBusyLevel(parseInt(e.target.value))}
                  className="w-full accent-primary"
                />
                <div className="flex justify-between text-xs text-gray-600 mt-1">
                  <span>Empty</span>
                  <span>Full</span>
                </div>
              </div>

              {/* Reservations */}
              <div className="card p-5">
                <h3 className="font-semibold text-white mb-4">Incoming Reservations</h3>
                {reservations.length === 0 ? (
                  <p className="text-gray-500 text-sm text-center py-8">No reservations yet</p>
                ) : (
                  <div className="space-y-3">
                    {reservations.map((res) => (
                      <div key={res.id} className="border border-dark-border rounded-xl p-4">
                        <div className="flex items-start justify-between">
                          <div>
                            <p className="font-medium text-white">{res.user.full_name}</p>
                            <p className="text-sm text-gray-500">{res.date} at {res.time} · {res.party_size} guests</p>
                            <p className="text-xs text-gray-600 capitalize mt-1">{res.reservation_type.replace('_', ' ')} · Ref: {res.reference}</p>
                          </div>
                          <span className={`badge ${
                            res.status === 'pending' ? 'bg-yellow-500/20 text-yellow-400' :
                            res.status === 'accepted' ? 'bg-green-500/20 text-green-400' :
                            'bg-red-500/20 text-red-400'
                          } capitalize`}>{res.status}</span>
                        </div>
                        {res.special_requests && (
                          <p className="text-xs text-gray-500 mt-2 italic">"{res.special_requests}"</p>
                        )}
                        {res.status === 'pending' && (
                          <div className="flex gap-2 mt-3">
                            <button onClick={() => handleReservationStatus(res.id, 'accepted')} className="flex-1 py-1.5 rounded-lg bg-green-500/20 text-green-400 text-sm font-medium hover:bg-green-500/30 transition-colors">Accept</button>
                            <button onClick={() => handleReservationStatus(res.id, 'rejected')} className="flex-1 py-1.5 rounded-lg bg-red-500/20 text-red-400 text-sm font-medium hover:bg-red-500/30 transition-colors">Decline</button>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </main>
          )}
        </div>
      )}
    </div>
  );
}
